const surnames=[{"slug":"li","hanzi":"李","pinyin":"Li","variants":"Lee, Lei","rank":1,"meaning":"Often explained through the character for plum or plum tree in modern reference contexts.","origin":"Li is one of the most common Chinese surnames and appears across many regional romanization systems.","keywords":["li surname origin","li surname meaning","li chinese surname"],"path":"/surnames/li/"},{"slug":"wang","hanzi":"王","pinyin":"Wang","variants":"Wong, Ong","rank":2,"meaning":"The character Wang means king or ruler.","origin":"Wang is widely used in Mandarin and appears as Wong or Ong in some Cantonese, Hokkien, or regional communities.","keywords":["wang surname origin","wang surname meaning","wong surname origin"],"path":"/surnames/wang/"},{"slug":"zhang","hanzi":"张","pinyin":"Zhang","variants":"Cheung, Chang","rank":3,"meaning":"The character is associated with drawing or stretching a bow.","origin":"Zhang is a major Mandarin surname with common romanized forms such as Cheung and Chang in overseas communities.","keywords":["zhang surname origin","zhang surname meaning","zhang chinese surname"],"path":"/surnames/zhang/"},{"slug":"liu","hanzi":"刘","pinyin":"Liu","variants":"Lau, Low","rank":4,"meaning":"The surname is usually treated as a lineage name rather than a simple literal-word surname.","origin":"Liu is historically important and strongly represented in Chinese history and overseas Chinese communities.","keywords":["liu surname meaning","liu surname origin","liu chinese surname"],"path":"/surnames/liu/"},{"slug":"chen","hanzi":"陈","pinyin":"Chen","variants":"Chan, Tan","rank":5,"meaning":"Chen is commonly connected with an ancient state name and lineage identity.","origin":"Chen is a very common Chinese surname, while Chan and Tan are common regional romanizations.","keywords":["chen surname meaning","chen surname origin","chan surname meaning"],"path":"/surnames/chen/"},{"slug":"yang","hanzi":"杨","pinyin":"Yang","variants":"Yeung","rank":6,"meaning":"The character is associated with poplar or willow-like trees in common explanations.","origin":"Yang is a common surname across Mandarin-speaking regions and appears as Yeung in some Cantonese romanization.","keywords":["yang surname origin","yang surname meaning","yang chinese surname"],"path":"/surnames/yang/"},{"slug":"huang","hanzi":"黄","pinyin":"Huang","variants":"Wong, Ng","rank":7,"meaning":"The character Huang means yellow.","origin":"Huang is common in Mandarin contexts; Wong and Ng can appear as related regional romanization forms depending on language and family history.","keywords":["huang surname origin","huang surname meaning","wong surname meaning"],"path":"/surnames/huang/"},{"slug":"zhao","hanzi":"赵","pinyin":"Zhao","variants":"Chao, Chiu","rank":8,"meaning":"Zhao is usually understood as a historical lineage and place-linked surname.","origin":"Zhao is famous as the first surname in the traditional Hundred Family Surnames text.","keywords":["zhao surname meaning","zhao surname origin","zhao chinese surname"],"path":"/surnames/zhao/"},{"slug":"wu","hanzi":"吴","pinyin":"Wu","variants":"Ng, Woo","rank":9,"meaning":"Wu is tied to a historical state and lineage identity.","origin":"Wu is common in Mandarin, while Ng and Woo are frequent overseas romanization forms.","keywords":["wu surname meaning","wu surname origin","ng surname origin"],"path":"/surnames/wu/"},{"slug":"zhou","hanzi":"周","pinyin":"Zhou","variants":"Chou, Chow","rank":10,"meaning":"Zhou is associated with an ancient dynasty and lineage tradition.","origin":"Zhou appears in Mandarin as Zhou and in older or regional romanizations as Chou or Chow.","keywords":["zhou surname meaning","zhou surname origin","zhou chinese surname"],"path":"/surnames/zhou/"}];const guideTargets=[{"title":"Chinese Surnames","path":"/chinese-surnames/","category":"Core Guides"},{"title":"Most Common Chinese Surnames","path":"/common-chinese-surnames/","category":"Reference Lists"},{"title":"Chinese Surname Meanings","path":"/chinese-surname-meaning/","category":"Meaning Guides"},{"title":"Chinese Surname Origins","path":"/chinese-surname-origin/","category":"Origin Guides"},{"title":"Hundred Family Surnames","path":"/hundred-family-surnames/","category":"Classic Text"},{"title":"Surname Lookup","path":"/surname-lookup/","category":"Tools"},{"title":"Rare Chinese Surnames","path":"/rare-chinese-surnames/","category":"Reference Lists"},{"title":"Chinese Surname Pronunciation","path":"/chinese-surname-pronunciation/","category":"Pronunciation"}];function resultLink(path,label){return '<div class="result-actions"><a class="button-link" href="'+path+'">'+label+'</a></div>'}function findSurname(q){q=String(q||'').trim().toLowerCase();return surnames.find(s=>s.pinyin.toLowerCase()===q||s.hanzi===q||s.variants.toLowerCase().split(/,\s*/).includes(q)||s.keywords.some(k=>k.includes(q)||q.includes(k.replace(/ surname (origin|meaning)/,''))))}document.querySelectorAll('[data-surname-form]').forEach(form=>form.addEventListener('submit',event=>{event.preventDefault();const data=new FormData(form);const found=findSurname(data.get('surname'));const goal=data.get('goal');const box=form.parentElement.querySelector('[data-surname-result]');box.hidden=false;if(found){const intro=goal==='origin'?found.origin:goal==='meaning'?found.meaning:'Open the profile or compare it with common surname lists.';box.innerHTML='<h3>'+found.pinyin+' surname '+found.hanzi+'</h3><p>'+intro+'</p>'+resultLink(found.path,'Open surname guide');return}const target=goal==='origin'?'/chinese-surname-origin/':goal==='meaning'?'/chinese-surname-meaning/':'/common-chinese-surnames/';box.innerHTML='<h3>No exact profile yet</h3><p>Use the broader guide while this surname is added to the publishing queue.</p>'+resultLink(target,'Open related guide');}));document.querySelectorAll('[data-site-search]').forEach(form=>form.addEventListener('submit',event=>{event.preventDefault();const q=String(new FormData(form).get('q')||'').toLowerCase().trim();if(!q){location.href='/guides/';return}const found=findSurname(q);if(found){location.href=found.path;return}const direct=[{pattern:/meaning/,path:'/chinese-surname-meaning/'},{pattern:/origin|history|ancestry/,path:'/chinese-surname-origin/'},{pattern:/common|list|top|popular/,path:'/common-chinese-surnames/'},{pattern:/hundred|baijiaxing|100 family/,path:'/hundred-family-surnames/'},{pattern:/pronunciation|pinyin|tone/,path:'/chinese-surname-pronunciation/'},{pattern:/rare|uncommon|compound/,path:'/rare-chinese-surnames/'}].find(item=>item.pattern.test(q));if(direct){location.href=direct.path;return}const match=guideTargets.find(item=>item.title.toLowerCase().split(' ').some(word=>word.length>3&&q.includes(word)));location.href=match?match.path:'/guides/';}));document.querySelectorAll('[data-guide-filter]').forEach(button=>button.addEventListener('click',()=>{document.querySelectorAll('[data-guide-filter]').forEach(item=>item.classList.remove('is-active'));button.classList.add('is-active');const value=button.dataset.guideFilter;document.querySelectorAll('[data-guide-card]').forEach(card=>{card.hidden=value!=='all'&&card.dataset.guideCategory!==value;});}));